                         p256_ecdsa_signature_t *signature_p256,
                         p256_point_t *pub_p256,
                         otcrypto_word32_buf_t *signature_mut,
                         size_t *digest_len) {
  if (uj_qx.coordinate_len > kP256CoordBytes) {
    LOG_ERROR(
        "Coordinate value qx too large for P256 (have = %d bytes, max = %d "
        "bytes)",
